<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --panel-color: #2d2d2d;
            --text-color: #e0e0e0;
            --accent-color: #4a90e2;
            --btn-hover: #3d3d3d;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            margin: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            overflow: hidden;
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
            padding: 20px;
            background: var(--panel-color);
            border-radius: 12px;
            box-shadow: 0 8px 32px rgba(0,0,0,0.5);
        }

        canvas {
            border: 2px solid #444;
            image-rendering: pixelated;
            cursor: crosshair;
            background-color: #000;
            max-width: 90vw;
            max-height: 70vh;
        }

        .controls {
            display: flex;
            gap: 10px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            padding: 10px 16px;
            border: none;
            border-radius: 4px;
            background: #444;
            color: white;
            cursor: pointer;
            transition: background 0.2s, transform 0.1s;
            font-weight: bold;
        }

        button:hover {
            background: var(--btn-hover);
        }

        button:active {
            transform: translateY(2px);
        }

        button.active {
            outline: 2px solid var(--accent-color);
            background: #555;
        }

        #clear {
            background: #a33;
        }

        #clear:hover {
            background: #c44;
        }
    </style>
</head>
<body>

<div class="container">
    <div class="controls" id="toolbar">
        <button id="mat-sand" class="active">Sand</button>
        <button id="mat-water">Water</button>
        <button id="mat-wall">Wall</button>
        <button id="mat-acid">Acid</button>
        <button id="mat-empty">Eraser</button>
        <button id="clear">Clear Grid</button>
    </div>
    <canvas id="sand" width="400" height="400"></canvas>
</div>

<script>
    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d', { alpha: false });
    const w = 100;
    const h = 100;
    const cellSize = canvas.width / w;

    let grid = Array(h).fill().map(() => Array(w).fill('empty'));
    let currentMaterial = 'sand';
    let isMouseDown = false;

    // Deterministic pseudo-random for tick() consistency
    let seed = 123456789;
    function prng() {
        seed = (seed * 16807) % 2147483647;
        return (seed - 1) / 2147483646;
    }

    const colors = {
        sand: '#e3b878',
        water: '#4a90e2',
        wall: '#555555',
        acid: '#a3ff00',
        empty: '#000000'
    };

    const sim = {
        w, h,
        get(x, y) {
            if (x < 0 || x >= w || y < 0 || y >= h) return 'wall';
            return grid[y][x];
        },
        set(x, y, material) {
            if (x >= 0 && x < w && y >= 0 && y < h) {
                grid[y][x] = material;
            }
        },
        clear() {
            grid = Array(h).fill().map(() => Array(w).fill('empty'));
        },
        tick(n) {
            for (let step = 0; step < n; step++) {
                const nextGrid = grid.map(row => [...row]);

                // Process bottom-up to prevent teleporting
                for (let y = h - 1; y >= 0; y--) {
                    for (let x = 0; x < w; x++) {
                        const current = grid[y][x];
                        if (current === 'empty' || current === 'wall') continue;

                        let tx = -1, ty = -1;

                        if (current === 'sand') {
                            // Fall down into empty/water/acid
                            if (y + 1 < h && (grid[y+1][x] === 'empty' || grid[y+1][x] === 'water' || grid[y+1][x] === 'acid')) {
                                tx = x; ty = y + 1;
                            } else {
                                // Slide diagonally
                                let dirs = [[x - 1, y + 1], [x + 1, y + 1]];
                                if (prng() > 0.5) [dirs[0], dirs[1]] = [dirs[1], dirs[0]];
                                for (let [dx, dy] of dirs) {
                                    if (dy < h && dx >= 0 && dx < w && (grid[dy][dx] === 'empty' || grid[dy][dx] === 'water' || grid[dy][dx] === 'acid')) {
                                        tx = dx; ty = dy;
                                        break;
                                    }
                                }
                            }
                        } else if (current === 'water' || current === 'acid') {
                            // Fall down into empty/acid
                            if (y + 1 < h && (grid[y+1][x] === 'empty' || grid[y+1][x] === 'acid')) {
                                tx = x; ty = y + 1;
                            } else {
                                // Spread horizontally into empty/acid
                                let dirs = [[x - 1, y], [x + 1, y]];
                                if (prng() > 0.5) [dirs[0], dirs[1]] = [dirs[1], dirs[0]];
                                for (let [dx, dy] of dirs) {
                                    if (dy >= 0 && dy < h && dx >= 0 && dx < w && (grid[dy][dx] === 'empty' || grid[dy][dx] === 'acid')) {
                                        tx = dx; ty = dy;
                                        break;
                                    }
                                }
                            }
                        }

                        if (tx !== -1) {
                            // Check if target is available in nextGrid to prevent double-occupancy
                            const targetMat = grid[ty][tx];
                            let canMove = false;
                            if (current === 'sand') {
                                if (nextGrid[ty][tx] === 'empty' || nextGrid[ty][tx] === 'water' || nextGrid[ty][tx] === 'acid') canMove = true;
                            } else {
                                if (nextGrid[ty][tx] === 'empty' || nextGrid[ty][tx] === 'acid') canMove = true;
                            }

                            if (canMove) {
                                nextGrid[ty][tx] = current;
                                nextGrid[y][x] = 'empty';
                            }
                        }

                        // Acid logic: Dissolve neighbors
                        if (current === 'acid') {
                            const neighbors = [[x, y + 1], [x - 1, y], [x + 1, y]];
                            for (let [nx, ny] of neighbors) {
                                if (ny >= 0 && ny < h && nx >= 0 && nx < w) {
                                    if (grid[ny][nx] === 'sand' || grid[ny][nx] === 'wall') {
                                        nextGrid[ny][nx] = 'empty';
                                    }
                                }
                            }
                        }
                    }
                }
                grid = nextGrid;
            }
        }
    };

    // UI Logic
    const buttons = document.querySelectorAll('#toolbar button:not(#clear)');
    buttons.forEach(btn => {
        btn.addEventListener('click', () => {
            buttons.forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            currentMaterial = btn.id.replace('mat-', '');
        });
    });

    document.getElementById('clear').addEventListener('click', () => sim.clear());

    // Interaction Logic
    function handleInput(e) {
        const rect = canvas.getBoundingClientRect();
        const scaleX = canvas.width / rect.width;
        const scaleY = canvas.height / rect.height;
        const mouseX = (e.clientX - rect.left) * scaleX;
        const mouseY = (e.clientY - rect.top) * scaleY;
        const gx = Math.floor(mouseX / cellSize);
        const gy = Math.floor(mouseY / cellSize);

        if (gx >= 0 && gx < w && gy >= 0 && gy < h) {
            sim.set(gx, gy, currentMaterial);
        }
    }

    canvas.addEventListener('mousedown', (e) => { isMouseDown = true; handleInput(e); });
    window.addEventListener('mouseup', () => { isMouseDown = false; });
    canvas.addEventListener('mousemove', (e) => { if (isMouseDown) handleInput(e); });

    // Rendering Loop
    function render() {
        ctx.fillStyle = '#000';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        for (let y = 0; y < h; y++) {
            for (let x = 0; x < w; x++) {
                const mat = grid[y][x];
                if (mat !== 'empty') {
                    ctx.fillStyle = colors[mat];
                    ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
                }
            }
        }

        sim.tick(1); // Run 1 step per frame
        requestAnimationFrame(render);
    }

    // Initialize and start
    render();

</script>
</body>
</html>
